mapper.update:
update emoji_category


        name = #{name},


        sort = #{sort},


        update_time = #{updateTime},


        status = #{status}


where id = #{id}

mapper.select:
select id, name, sort, create_time, status from emoji_category


         status = #{status}


order by sort

select e.id, e.url, e.content, ec.name, u.nick_name as creatorName, e.create_time, e.status from emoji e left join emoji_category ec on e.category_id = ec.id inner join user u on e.creator_id = u.id
and e.status = #{status}
and e.category_id = #{categoryId} and ec.status = 1
